export type AirportInfo = {
  /** IATA airport code (e.g. "TPE") */
  code: string;
  /** Full airport name */
  name: string;
  /** City name */
  city: string;
  /** Country name */
  country: string;
  /** Latitude in degrees */
  latitude: number;
  /** Longitude in degrees */
  longitude: number;
};

/** Reference to an airport: either an IATA code string or [longitude, latitude] tuple */
export type AirportRef = string | [number, number];

